function transform(s) {
  const input = s.input || '';
  try {
    switch (s.op) {
      case 'base64-encode': return { output: btoa(unescape(encodeURIComponent(input))) };
      case 'base64-decode': return { output: decodeURIComponent(escape(atob(input))) };
      case 'url-encode':    return { output: encodeURIComponent(input) };
      case 'url-decode':    return { output: decodeURIComponent(input) };
      case 'json-prettify': return { output: JSON.stringify(JSON.parse(input), null, 2) };
      case 'json-minify':   return { output: JSON.stringify(JSON.parse(input)) };
      default: return { output: '' };
    }
  } catch (e) {
    return { output: 'Error: ' + e.message };
  }
}
